INSERT INTO "public"."asanas" ("name", "id", "iast", "plate_numbers", "intensity", "requires_sides", "page_2001", "page_2015", "technique", "category_legacy", "note", "stages", "english_name", "last_edited", "description", "is_system", "recovery_pose_id", "preparatory_pose_id", "how_to_use_yoga_id", "yoga_the_iyengar_way_id", "devanagari", "translation", "oracle_lore", "symbol_prompt", "is_curated", "image_url", "audio_url", "page_primary", "variation_code", "category_id", "hold_json", "gem_plate", "is_restorative") VALUES
	('Kasyapasana', '150', 'KaÅ›ypÄsana', 'Final: 399, 400', 19, true, 311, 257, 'Begin in a side plank position. Place the top foot into half lotus. Catch the big toe from behind the back. This relieves sacral stiffness. This strengthens the hands.', '08_Advanced_Leg_behind_Head', NULL, NULL, 'Kasyapaâ€™s Pose', '14/2/2026 4:12pm', 'Kasyapasana or Progenitor pose
The technique involves a side plank with the top foot in half lotus, catching the big toe from behind the back.
Effects: Relieves sacral stiffness, strengthens hands.', true, NULL, NULL, NULL, NULL, 'à¤•à¤¶à¥à¤¯à¤ªà¤¾à¤¸à¤¨', '"Kasyapa''s Pose"; Kasyapa referring to an ancient sage.', 'Kasyapasana requires deep hip flexion and adduction in the bound leg, facilitating a spinal twist. The free leg extends laterally, demanding significant hamstring flexibility and balance while maintaining spinal extension.', 'Two parallel lines represent the grounding legs. Concentric arcs originate from one line and extend toward the other, depicting the spiraling action of the torso.', true, '/storage/v1/object/public/yoga-cards/150_master_kasypasana.webp', '/storage/v1/object/public/audio-assets/150_kasyapasana.mp3', NULL, NULL, 7, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Viparita Karani', '235', 'ViparÄ«takaraá¹‡Ä«', '', 1, false, NULL, NULL, 'Set Up: Sit with your side against a wall. Use a folded blanket or bolster to support your lower back/hips.
Enter the Pose: Exhale, gently lie on your back, and swing your legs up onto the wall.
Adjust: Your hips can be flush against the wall for a deep stretch, or slightly away for comfort. Your sit bones should feel supported.
Relaxation: Rest your arms to the sides with palms up, or place them on your belly. Keep your neck and shoulders relaxed.
Hold: Maintain the pose for 3 to 15 minutes, breathing deeply and slowly.
Exit: Gently bend your knees, roll to one side, and stay for a few breaths before sitting up.', NULL, NULL, NULL, 'Legs up the wall with raised hips', '22/2/2026 1:02pm', 'Viparita Karani, or Legs-Up-The-Wall Pose, is a gentle restorative inversion where the practitioner lies on their back with their legs resting vertically against a wall. Its benefits include:  - Reduces stress, anxiety, and calms the nervous system
  - Improves circulation and reduces swelling in the legs and feet
  - Alleviates lower back pain and muscle tension
  - Enhances sleep quality and aids in relaxation
  - Supports lymphatic drainage and immune system function
  - Promotes better digestion by activating the parasympathetic state
  - Relieves tired legs, feet cramps, and menstrual discomfort', true, NULL, NULL, '40', '122', 'à¤µà¤¿à¤ªà¤°à¥€à¤¤à¤•à¤°à¤£à¥€', '"Inverted Action," referring to the reversed gravitational effect on the body.', 'The pose utilizes the wall as a primary structural support, creating a right angle at the hip crease. Consistent adductor engagement initiates the return of venous blood flow.', 'Within a square frame, a vertical hairline ascends from the bottom edge. Three concentric semi-circular arcs, their open ends facing upwards, are stacked above it, representing the progressive lift of the pelvic floor.', true, '/storage/v1/object/public/yoga-cards/235_master_viparitakarani.webp', '/storage/v1/object/public/audio-assets/235_ViparitaKarani.mp3', 122.00, NULL, 4, '{"flow": 5, "long": 600, "short": 300, "standard": 450}', '[]', true),
	('Bhramari Pranayama', '208', 'BhrÄmarÄ« PrÄá¹‡ÄyÄma', 'Final: 606', 1, false, NULL, 378, 'Sit in padmasana, siddhasana, swastikasana, virasana, or any convenient and comfortable meditative position. Keep the back and the spinal column firm. Soften the spinal muscles to allow the torso to adjust during the breath. Lower the head toward the trunk. Lift the inner frame of the chest toward the descending chin. Rest the chin in the notch above the breastbone to form the chin lock (Jalandhara Bandha). Place the back of the wrists on the knees with the arms down. Join the tip of the index finger of each hand with the tip of the thumb to form ja mudra while keeping the other fingers extended. Close the eyes and keep the eye-balls passive and receptive. Direct the gaze inwards toward the heart. Keep the inner ears alert and receptive. Exhale whatever breath is in the lungs through both nostrils. Raise the hands to the face to perform sanmukhi mudra. Lift the elbows to the level of the shoulders. Place the thumb tips in the ear holes to block out external sounds as part of sanmukhi mudra. Press the tragi over the ear holes if the thumb tips cause pain. Bring the index and middle fingers over the closed eyelids. Draw the upper lids down with the pads of the middle finger tips. Cover the remaining space above with the pads of the index finger tips to keep out light. Press the eye balls gently with the fingers while keeping them passive. Place the ring finger tips on the nostrils to narrow the nasal passages. Rest the little fingers on the upper lips to monitor the flow of the breath. Inhale slowly and deeply through both nostrils with a soft sibilant sound. Expand the chest fully without using force. Exhale slowly while creating a steady humming or murmuring sound like a bee. Feel the vibrations of the sound throughout the head. Complete these cycles for ten to fifteen minutes or until no strain is felt. Finish the final cycle by inhaling normally through both open nostrils. Lower the hands from the sanmukhi mudra position to the knees. Raise the head to a neutral position. Lie down flat in savasana and rest the entire body.', '10_Restorative_Pranayama', NULL, NULL, 'Humming Bee Breath', '14/2/2026 4:12pm', 'Bhramari Pranayama
It is a breathing technique where a soft humming sound like the murmuring of bees is made during exhalation.
Effects: The soft humming sound produced during exhalation is helpful in treating cases of insomnia, it also soothes the nerves, and tones the entire system.', true, NULL, NULL, NULL, NULL, 'à¤­à¥à¤°à¤¾à¤®à¤°à¥€ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Bhramari" refers to the buzzing of a bee; "Pranayama" is breath control.', 'This pranayama structurally utilizes the natural vibration of the humming sound to subtly affect the cranial nerves and calm the nervous system; the closed ear passages focus the internal vibration.', 'Within a square frame, a vertical hairline is offset to the left. An open circle sits on the right, bisected by the top edge of the square, representing the open glottis. A short horizontal line intersects the vertical line, weighted to the left, near the base, signifying grounded awareness.', true, '/storage/v1/object/public/yoga-cards/208_master_bhramari_pranayama.webp', '/storage/v1/object/public/audio-assets/208_bhramaripranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Nadi Sodhana Pranayama', '205', 'NÄá¸Ä« Åšodhana PrÄá¹‡ÄyÄma', 'Final: 600', 2, false, NULL, 373, 'Sit in a comfortable meditative posture such as the lotus pose or the hero pose. Keep the back erect and rigid. Lift the chest toward the chin. Lower the head toward the trunk. Rest the chin in the notch between the collarbones to form the chin lock (Jalandhara Bandha). Stretch the left arm forward. Rest the back of the left wrist on the left knee. Join the index finger and thumb of the left hand to form the ja mudra. Bend the right arm at the elbow. Fold the index and middle fingers of the right hand toward the palm. Keep the right thumb near the right nostril. Place the right ring and little fingers on the left side of the nose. Position the fingertips just below the nasal bone and above the fatty tissue, inhale through both nostrils. Empty the lungs completely through the right nostril. Control the aperture of the right nostril with the inner side of the right thumb, away from the nail. Now inhale slowly, steadily, and deeply through the right nostril. Control the aperture with the tip of the right thumb near the nail. Fill the lungs to the brim, which is pÅ«raka. Completely block the left nostril using the ring and little fingers during this inhalation. After full inhalation, completely block the right nostril with pressure from the thumb. Release the pressure of the ring and little fingers on the left nostril. Readjust the ring and little fingers on the outer edge of the left nostril. Keep the ring and little fingers parallel to the septum. Exhale slowly, steadily, and deeply through the left nostril. Empty the lungs completely, which is rechaka. Exert pressure from the inner sides of the tips of the ring and little fingers, away from the nails. After full exhalation through the left nostril, change the pressure on the left nostril by adjusting the fingers. In the changed position, the tips of the ring and little fingers nearer the nails exert the pressure. Now inhale through the left nostril slowly, steadily, and deeply. Fill the lungs to the brim, which is pÅ«raka. After full inhalation through the left nostril, block it. Exhale through the right nostril. Adjust the pressure of the right thumb on the right nostril as stated previously. This completes one cycle. Perform eight to ten cycles at a stretch. After the final inhalation through the left nostril you can exhale through both nostrils to complete the sequence. Conclude by lying down in Savasana.', '10_Restorative_Pranayama', NULL, 'Ia,Ib,IIa,IIb,IIIa,IIIb,IVa,IVb', 'Alternate Nostril Breathing', '14/2/2026 4:12pm', 'NÄá¸Ä« Åšodhana PrÄnÄyÄma

Technique

1. Sit in any comfortable position like Padmasana (Image 104), Siddhasana (Image 84) or Virasana (Image 89).

2. Keep the back erect and rigid. Lower the head to the trunk. Rest the chin in the notch between the collar-bones just above the breast-bone. (This is Jalandhara Bandha.)

3. Stretch the left arm. Rest the back of the left wrist on the left knee. Perform JÃ±Äna Mudra with the left hand (as stated in stage 3 of the technique of Ujjayi).

4. Bend the right arm at the elbow. Bend the index and middle fingers towards the palm, keeping them passive. Bring the ring and little fingers towards the thumb. (Image 598)

5. Place the right thumb on the right side of the nose just below the nasal bone, the ring and little fingers on the left side of the nose just below the nasal bone, just above the curve of the fatty tissue of the nostrils above the upper jaw.

6. Press the ring and the little finger to block the left side of the nose completely.

7. With the right thumb, press the fatty tissue on the right side so as to make the outer edge of the right nostril parallel to the lower edge of the cartilage of the septum.

8. The right thumb is bent at the top joint and the tip of the thumb is placed at a right angle to the septum. (Image 599)

9. Empty the lungs completely through the right nostril. Control the aperture of the right nostril with the inner side of the right thumb, away from the nail.

10. Now inhale slowly, steadily and deeply through the right nostril, controlling the aperture with the tip of the right thumb near the nail. Fill the lungs to the brim (pÅ«raka). During this inhalation the left nostril is completely blocked by the ring and little fingers.

11. After full inhalation, block the right nostril completely with the pressure of the thumb and release the pressure of the ring and little fingers on the left nostril. Readjust them on the outer edge of the left nostril and keep it parallel to the septum. Exhale slowly, steadily and deeply through the left nostril. Empty the lungs completely. The pressure should be exerted from the inner sides of the tips of the ring and little fingers (away from the nails) (rechaka).

12. After full exhalation through the left nostril, change the pressure on it by adjusting the fingers. In the changed position, the tips of the ring and little fingers nearer the nails exert the pressure.

13. Now inhale through the left nostril slowly, steadily and deeply, filling the lungs to the brim (pÅ«raka).

14. After full inhalation through the left nostril, block it and exhale through the right nostril, adjusting the pressure of the right thumb on the right nostril as stated in para. 2 above (rechaka).

15. This completes one cycle of NÄá¸Ä« Åšodhana PrÄnÄyÄma. Here the rhythm of breathing is as follows:

===>a. Exhale through the right nostril.
===>b. Inhale through the right nostril.
===>c. Exhale through the left nostril.
===>d. Inhale through the left nostril.
===>e. Exhale through the right nostril.
===>f. Inhale through the right nostril.
===>g. Exhale through the left nostril.
===>h. Inhale through the left nostril.
===>i. Exhale through the right nostril.
===>j. Inhale through the right nostril ... and so on.

Stage (a) above is the preparatory one. The first real NÄá¸Ä« Åšodhana PrÄnÄyÄma cycle starts at stage (b) and ends at stage (e). The second cycle starts at stage (f) and ends at stage (i). Stage (j) is the safety measure to be observed after the completion of the cycles in order to prevent gasping, breathlessness and strain on the heart.

Do 8 to 10 cycles at a stretch as described above. This may take 6 or 8 minutes.

Inhalation and exhalation from each side should take the same time. In the beginning the duration will be unequal. Persevere until equality is achieved.

After achieving mastery over the equal duration and precision over inhalation and exhalation on either side an attempt may be made to retain breath (antara kumbhaka) after inhaling.

This precision is only achieved after long practice.

Retention should not disturb the rhythm and equality of inhalation and exhalation. If either are disturbed curtail the period of retention or hold the breath on alternate cycles.

During retention after inhalation practise MÅ«la Bandha (see p. 366).

Do not attempt to hold the breath after exhalation (bÄhya kumbhaka, Image 600) until you have mastered retention after inhalation (antara kumbhaka). Then during bÄhya kumbhaka practise Uddiyana (Images 593, 594) with MÅ«la Bandha (see p. 366).

Retention and the lengthening of inhalation and exhalation should only be attempted with the help and under the guidance of an experienced Guru.

Always conclude by lying down in Savasana. (Image 592)

Effects Increases oxygen supply to the blood, refreshing the body; calms and purifies the nerves; stills and clears the mind (lucidity).

Note: Persons with high blood pressure or heart trouble should not hold their breath (kumbhaka). Persons with low blood pressure benefit from internal retention.', true, NULL, NULL, NULL, NULL, 'à¤¨à¤¾à¤¡à¤¼à¥€ à¤¶à¥‹à¤§à¤¨ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', 'Alternate Nostril Breathing', 'Nadi Shodhana involves diaphragmatic breathing and expansion of the rib cage; the spinal extensors engage to maintain an upright posture, resisting kyphosis. Controlled abdominal contraction assists in exhalation, activating the transverse abdominis and internal obliques to support the breath and stabilize the core.', 'The symbol consists of a square frame representing stability, with three intersecting lines within. The lines symbolize the Ida, Pingala, and Sushumna nadis converging, representing balance and harmony.', true, '/storage/v1/object/public/yoga-cards/205_master_nadi_sodhana_pranayama.webp', '/storage/v1/object/public/audio-assets/205_nadisodhanapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 900, "short": 600, "standard": 750}', '[]', false),
	('Nasa Mudra', '232', 'NÄsÄ MudrÄ', 'Final: 142 | Int: 109, 110, 111, 112, 113, 114, 115, 116, 117, 118, 119, 120, 121, 122, 123, 124, 125, 126, 127, 128, 129, 130, 131, 132, 133, 134, 135, 136, 137, 138, 139, 140, 141', 1, false, NULL, NULL, 'Sit with the spine erect. Raise the right hand and bend the index and middle fingers toward the palm (Vishnu Mudra). Place the thumb on the right side of the nose and the ring and little fingers on the left side, just below the nasal bone where the flesh is soft. The art of placement requires the fingers to move like a balance scaleâ€”as one side opens, the other narrows with subtle, firm, yet light pressure. Ensure the fingers do not pull the nose to either side; the bridge of the nose should remain centered. The elbow should be relaxed and tucked close to the chest to keep the hand steady and the arm from fatiguing.', '10_Restorative_Pranayama', 'This entry focuses on the precise art of digital nostril control, rather than the breathing cycle itself.', NULL, 'Digital Pranayama', '14/2/2026 4:12pm', 'Digital Pranayama (Nasa Mudra)
The art of using the fingers (digits) to refine the flow of air. This technique focuses on the subtle placement and movement of the hand to control the nostrils without disturbing the equilibrium of the head or neck.
Effects: Develops sensitivity in the fingertips, ensures an even flow of air through the nasal passages, and prepares the practitioner for the advanced stages of controlled respiration.', true, NULL, NULL, NULL, NULL, 'à¤¨à¤¾à¤¸à¤¾à¤®à¥à¤¦à¥à¤°à¤¾', 'Nasa: Nose; Mudra: Seal/Gesture. Gesture of the Nose.', 'Stabilizes the Muladhara chakra via focused breath. Rooting action initiates from the perineum, drawing energy upward through the central channel.', 'A diagonal slash ascends from left to right, representing the upward flow of prana. An equilateral triangle is positioned at the base of the slash, grounding the energy in the earth.', true, '/storage/v1/object/public/yoga-cards/232_master_nasa_mudra.webp', '/storage/v1/object/public/audio-assets/232_NasaMudra.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Pranamasana', '225', 'Praá¹‡ÄmÄsana', NULL, 1, false, NULL, NULL, 'Stand tall with the feet together, rooting down firmly through the soles. Bring the palms together at the heart center in Anjali Mudra. Ensure the spine is straight, the core is lightly engaged, and the shoulders are relaxed away from the ears. Maintain a soft gaze straight ahead or gently close the eyes. Focus on deep, calm breaths to center the mind and express gratitude. Hold the position while maintaining a vertical line from the crown of the head through the center of the body to the heels, ensuring the weight is distributed evenly across both feet.', '11_Ayurvedic_Toning', 'Focus on the firm connection between the palms and the grounding of the feet.', NULL, 'Standing Prayer Pose', '14/2/2026 4:12pm', 'Pranamasana (Prayer Pose)
Pranamasana is a grounding posture symbolizing reverence, gratitude, and connection. It is used to center the mind and honor the inner self at the beginning or end of a practice.
Effects: Fosters peace and humility, centers the mind, improves balance, and establishes a calm respiratory rhythm.', true, NULL, NULL, NULL, NULL, 'à¤ªà¥à¤°à¤£à¤¾à¤®à¤¾à¤¸à¤¨', 'Pra- (forward, forth), Namas- (bow, obeisance), Asana (posture): Posture of reverence.', 'The pose establishes the foundation for standing postures, emphasizing adductor engagement and sacral alignment. Proper execution requires conscious effort to maintain a neutral spine and evenly distribute weight.', 'Within a square frame, a diagonal slash ascends from the bottom left to the top right, representing the flow of energy. A solid bindu resides near the midpoint of the slash, weighted slightly toward the bottom of the frame, signifying grounded awareness.', true, '/storage/v1/object/public/yoga-cards/225_master_pranamasana.webp', '/storage/v1/object/public/audio-assets/225_pranamasana.mp3', NULL, NULL, 11, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Kapalabhati Pranayama', '207', 'KapÄlabhÄti PrÄnÄyÄma', 'Final: 605', 4, false, NULL, 378, 'Sit nicely in Padmasana or Sukhasana position. Close your eyes. Roll the shoulders back. Make sure your spine is well-lifted. Take some deep, steady breaths. Allow the abdomen to expand as you inhale. In KapÄlabhÄti, perform slow inhalation. Exhale vigorously. Retain the breath for a split second after each exhalation. Do a few cycles of KapÄlabhÄti. Lie down in Savasana after finishing KapÄlabhÄti. In BhastrikÄ, inhale and exhale quickly ten times like the bellows of the blacksmith. Constantly dilate and contract. Stop immediately if the nose starts to bleed. Stop immediately if the ears throb and ache.', '10_Restorative_Pranayama', NULL, 'I,II,III,IV', 'Skull-Shining Breath', '14/2/2026 4:12pm', 'KapÄlabhÄti PrÄnÄyÄma
The process or kriya of KapÄlabhÄti is a milder form of BhastrikÄ PrÄnÄyÄma, where the inhalation is slow but the exhalation is vigorous, with a split second of retention after each exhalation.
Effects: Both BhastrikÄ and KapÄlabhÄti activate and invigorate the liver, spleen, pancreas and abdominal muscles, thus digestion is improved, the sinuses are drained, the eyes feel cool and one has a general sense of exhilaration.', true, NULL, NULL, NULL, NULL, 'à¤•à¤ªà¤¾à¤²à¤­à¤¾à¤¤à¤¿ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', 'Skull Shining Breath (Variation of Root Pose)', 'Kapalabhati involves forceful exhalations driven by rapid contractions of the abdominal muscles, specifically the rectus abdominis, while passively inhaling. This action massages the visceral organs and stimulates the respiratory passages, promoting the expulsion of toxins.', 'The symbol consists of two parallel horizontal lines, representing the duality of inhalation and exhalation, with a solid bindu (dot) placed centrally above them, symbolizing the focus and concentrated energy required during the practice.', true, '/storage/v1/object/public/yoga-cards/207_master_kapalabhati_pranayama.webp', '/storage/v1/object/public/audio-assets/207_kapalabhatipranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Sama Vrtti Pranayama', '211', 'Samavá¹›tti PrÄá¹‡ÄyÄma', 'Final: 608', 1, false, NULL, 380, 'Breathe through your nose only. Try not to move your shoulders, neck, chest, or upper body. Expand your lower belly outwardly on your inhale. Contract your lower belly inwardly on your exhale. Confine the practice initially only to inhalation and exhalation. First, achieve uniformity of length of time in inhalation and exhalation. Then, only attempt retention of breath after full inhalation. Start the retention gradually. In the beginning, keep the ratio time for inhalation, retention, and exhalation at one to one half to one. Very slowly increase the proportions to one to three quarters to one. After this is firmly established, attempt one to one to one. Only after mastering this, increase the proportion of retention so as to achieve the ratio of one to one to one. Do not attempt restraint of breath after full exhalation until you have achieved the desired ratio of one to one to one in inhalation, retention, and exhalation. Do not do both retentions together in the beginning. Practice retention after full inhalation and restraint after full exhalation separately or alternately. Practice retentions first by interspersing them after two or three cycles of deep breathing with inhalation and exhalation alone. Start with three retentions after full inhalation and three restraints after full exhalation. Increase the number of retentions very gradually.', '10_Restorative_Pranayama', NULL, NULL, 'Equal Ratio Breathing', '14/2/2026 4:12pm', 'Sama Vrtti Pranayama
Sama means the same or identical, straight, entire, whole and complete, also similarly or in the same manner, while Vrtti means action, movement, function or operation, a course of conduct or method.
Effects: Establishes uniformity in the duration of inhalation, retention, and exhalation, trains the lungs to handle vacuum and pressure without strain, prepares the mind for concentration (dharana) and meditation.', true, NULL, NULL, NULL, NULL, 'à¤¸à¤®à¤µà¥ƒà¤¤à¥à¤¤à¤¿ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', 'Sama (equal, same), Vrtti (fluctuations, activity, condition), Pranayama (breath control, life force extension).', 'Sama Vrtti focuses on equalizing the inhalation, exhalation, and pauses. The structural key involves diaphragmatic control and spine elongation to facilitate even breath distribution throughout the torso.', 'Within a square frame, a vertical hairline is centrally placed. A filled circle resides at the base of the line, symbolizing the engaged navel point. Above the circle, a concave arc intersects the vertical line, depicting the lifted diaphragm.', true, '/storage/v1/object/public/yoga-cards/211_master_samavrtti_pranayama.webp', '/storage/v1/object/public/audio-assets/211_samavrttipranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Viloma Pranayama', '213', 'VÄ«loma PrÄá¹‡ÄyÄma', 'Final: 610', 2, false, NULL, 383, 'Viloma PrÄnÄyÄma can be done seated or lying down. If seated, keep the back erect. Lower the head to the trunk. Rest the chin in the notch between the collar-bones and the breastbone for Jalandhara Bandha. Keep the hands in JÃ±Äna Mudra. Inhale for two seconds. Pause for two seconds holding the breath. Again inhale for two seconds. Again pause for two seconds holding the breath. Continue this until the lungs are completely full. Practice MÅ«la Bandha during the pauses in inhalation. Hold the breath for five to ten seconds according to capacity, practicing MÅ«la Bandha. Exhale slowly and deeply as in Ujjayi with an aspirate sound. Relax MÅ«la Bandha during exhalation. This completes one cycle of the first stage. Repeat ten to fifteen cycles of this first stage at a stretch. Rest for one or two minutes. For Stage two, take a deep breath without any pauses as in Ujjayi with a sibilant sound. Keep the chin on the top of the breast-bone. Fill the lungs completely. Hold the breath from five to ten seconds, keeping the MÅ«la Bandha grip. Exhale for two seconds. Pause for two seconds. Again exhale for two seconds. Again pause for two seconds. Continue this until the lungs are completely emptied. Maintain the MÅ«la Bandha grip during the pauses. This completes one cycle of the second stage. Repeat the second stage of Viloma ten to fifteen times at a stretch. Lie down in Savasana.', '10_Restorative_Pranayama', NULL, 'I,II,III,IV,V,VI,VII,VIII,IX', 'Interrupted Breathing', '14/2/2026 4:12pm', 'Viloma PrÄnÄyÄma
Viloma PrÄnÄyÄma is a breathing technique performed in two stages, involving either interrupted inhalation or interrupted exhalation.
Effects: Stage one helps those with low blood pressure, Stage two (lying down) benefits those with high blood pressure.', true, NULL, NULL, NULL, NULL, 'à¤µà¤¿à¤²à¥‹à¤® à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Against the grain" or "interrupted" breath control.', 'This breathing technique emphasizes conscious manipulation of the breath cycle, optimizing gaseous exchange. The core structural elements involve controlled pauses after inhalation and exhalation phases to refine interoceptive awareness.', 'Within a square frame, a central vertical line represents the spine. Two diagonal lines intersect this vertical line: one slanting upwards from the bottom left, the other downwards from the top right. A solid bindu marks the intersection point, signifying interrupted breath.', true, '/storage/v1/object/public/yoga-cards/213_master_viloma_pranayama.webp', '/storage/v1/object/public/audio-assets/213_vilomapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Sahita and Kevala Kumbhaka Pranayama', '216', 'Sahita and Kevala Kumbhaka PrÄá¹‡ÄyÄma', 'Final: 602', 4, false, NULL, 386, 'When breath retention is instinctive and occurs without deliberate action, it is known as Kevala Kumbhaka. Sahita Kumbhaka is the term used when retention is performed with intentional aid or deliberate accompaniment.', '10_Restorative_Pranayama', 'No plate number in book, image on page 388', NULL, 'Breath Retention with and without Support', '14/2/2026 4:12pm', 'Sahita and Kevala Kumbhaka Pranayama

Sahita means accompanied by or associated with and refers to breath retention performed with intentional effort whereas Kevala means absolute or perfect and refers to a state where breath retention becomes instinctive and natural.

Effects: drives away impurities of the body, drives away impurities of the mind, allows the divine fire within to blaze forth, makes the mind fit for concentration, makes the mind fit for meditation.', true, NULL, NULL, NULL, NULL, 'à¤¸à¤¹à¤¿à¤¤à¤•à¥‡à¤µà¤²à¤•à¥à¤®à¥à¤­à¤•à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', 'Sahita and Kevala Kumbhaka Pranayama (Variation of Root Pose)', 'In this variation, the muladhara bandha engages the pelvic floor, drawing the perineum inward and upward. Simultaneously, the frontal iliac spines lift as the sacrum broadens, stabilizing the lumbar spine.', 'The symbol features a vertical axis slightly offset to the side, representing the subtle asymmetry of the pose and breath. A solid bindu is placed at the center, symbolizing the grounding and centering effect of muladhara bandha.', true, '/storage/v1/object/public/yoga-cards/216_master_sahita_and_kevala_kumbhaka_pranayama.webp', '/storage/v1/object/public/audio-assets/216_sahitaandkevalakumbhakapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Anuloma Pranayama', '214', 'Anuloma Viloma PrÄá¹‡ÄyÄma', 'Final: 611', 2, false, NULL, 384, 'Sit in any comfortable position like Padmasana, Siddhasana, or Virasana. Keep the back erect and rigid. Lower the head to the trunk. Rest the chin in the notch between the collar-bones (Jalandhara Bandha). Inhale deeply through both nostrils as in Ujjayi until the lungs are fully filled. Hold the breath after inhalation (antara kumbhaka) from five to ten seconds, according to capacity. Maintain Mula Bandha by squeezing the entire perineal region inward and upward. Bring the right hand to the nose, placing the thumb on the right nostril and the ring finger on the left nostril. Release the Mula Bandha. Exhale slowly from the partially opened right nostril, keeping the left one completely blocked. Completely empty the lungs. Lower the hand. Inhale through both nostrils until the lungs are filled. Hold the breath after inhalation (antara kumbhaka) from five to ten seconds, according to capacity. Maintain Mula Bandha. Bring the right hand to the nose again. Release the Mula Bandha. Close the right nostril completely. Keep the left nostril partially open. Exhale slowly through left nostril and deeply to completely empty the lungs. This completes one cycle of Anuloma Pranayama. Perform five to eight cycles at a stretch. Then lie down in Savasana.', '10_Restorative_Pranayama', NULL, 'Ia,Ib,IIa,IIb,IIIa,IIIb,IVa,IVb,Va,Vb,VIa,VIb,VIIa,VIIb,VIIIa,VIIIb', 'Interrupted Inhalation', '14/2/2026 4:12pm', 'Anuloma Pranayama
Anu means with, along with or connected also in an orderly succession. Anuoma therefore means in regular gradation.with the hair (loma), along the grain or in natural order. In Anuloma Pranayama inhalation is done through both nostrils and exhalation alternating through either nostril, inhaling deeply through both nostrils, holding the breath for five to ten seconds while maintaining Mula Bandha, exhaling through alternating nostrils, and completing five to eight cycles.
Effects: Same effects as Ujjayi, Nadi Sodhana, and Surya Bhedana.', true, NULL, NULL, NULL, NULL, 'à¤…à¤¨à¥à¤²à¥‹à¤® à¤µà¤¿à¤²à¥‹à¤® à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Alternate Nostril Breathing"; ''Anu'' (with), ''loma'' (hair; against the grain); systematic breath control.', 'Anuloma Pranayama balances nervous system through regulated inhalation and exhalation. Spinal column remains erect, diaphragm engages for controlled breath.', 'Within a square frame, an equilateral triangle points downwards. A single vertical hairline bisects the triangle from its apex to the top edge of the square, weighted slightly toward the base of the triangle.', true, '/storage/v1/object/public/yoga-cards/214_master_anuloma_viloma_pranayama.webp', '/storage/v1/object/public/audio-assets/214_anulomapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Pratiloma Pranayama', '215', 'Pratiloma PrÄá¹‡ÄyÄma', 'Final: 612', 2, false, NULL, 385, 'Sit in a comfortable position such as the lotus pose or the hero pose. Keep the back erect and rigid. Lower the head toward the trunk. Rest the chin in the notch above the breastbone to form the chin lock (Jalandhara Bandha). Stretch the left arm forward. Rest the back of the left wrist on the left knee. Perform the ja mudra with the left hand by joining the thumb and index finger. Bend the right arm at the elbow. Fold the index and middle fingers of the right hand toward the palm. Bring the ring and little fingers toward the thumb to form mrigi mudra.  Place the right thumb and fingers on the sides of the nose just below the nasal bone. Press the ring and little fingers to block the left nostril completely. Use the right thumb to narrow the right nasal passage. Align the outer edge of the right nostril parallel to the septum. Inhale slowly and deeply through the right nostril. Fill the lungs to the brim. Block the right nostril so both sides of the nose are closed. Apply the root lock (Mula Bandha) by contracting the pelvic floor.  Hold the breath for five to ten seconds. Lower the right hand to the knee. Release the root lock (Mula Bandha). Exhale slowly and deeply through both nostrils as in ujjayi until the lungs are empty. Raise the right hand to the nose again. Block the right nostril completely with the thumb. Narrow the left nostril with the ring and little fingers. Inhale slowly and deeply through the left nostril. Fill the lungs to the brim. Block both nostrils with the fingers and thumb. Hold the breath and apply the root lock (Mula Bandha) for five to ten seconds. Lower the right hand. Release the root lock (Mula Bandha). Exhale slowly and deeply through both nostrils as in ujjayi. Repeat this sequence for five to eight cycles. Lie down in the corpse pose (Savasana).', '10_Restorative_Pranayama', NULL, 'Ia,Ib,IIa,IIb,IIIa,IIIb,IVa,IVb', 'Interrupted Exhalation', '14/2/2026 4:12pm', 'Pratiloma Pranayama
Prati means opposite. This type of Pranayama is the converse of Anuloma it is the inhalation through alternating nostrils then exhalation through both nostrils as in Ujjayi.
Effects: Same effects as Ujjayi, Nadi Sodhana, and Surya Bhedana, Difficult due to rhythm variation (inhalation longer than exhalation), only for advanced pupils, Hazardous for BP/heart/nervous disorders.', true, NULL, NULL, NULL, NULL, 'à¤ªà¥à¤°à¤¤à¤¿à¤²à¥‹à¤® à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Against the natural flow" breath technique.', 'Pratiloma Pranayama involves inhaling in stages while holding the breath between each inhalation. The structural blueprint includes controlled glottal engagement and precise regulation of respiratory muscles.', 'Within a square frame, two parallel vertical lines represent the lungs. An equilateral triangle, apex pointing downwards and slightly overlapping the bottom of the lines, signifies controlled breath retention.', true, '/storage/v1/object/public/yoga-cards/215_master_pratiloma_pranayama.webp', '/storage/v1/object/public/audio-assets/215_pratilomapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Bhastrika Pranayama', '206', 'BhasrÄ«kÄ PrÄá¹‡ÄyÄma', 'Final: 604', 4, false, NULL, 377, 'Sit comfortably with an erect spine in Siddhasana, Sukhasana, or Padmasana. Prepare by following the initial Ujjayi breathing technique. Take a fast, vigorous breath through both nostrils. Exhale fast and forcefully through both nostrils. Complete the inhalation and exhalation for ten to twelve cycles in a continuous flow. Take a slow, deep breath using the Ujjayi technique. Retain the breath with MÅ«la Bandha for two to three seconds. Exhale slowly and deeply as in Ujjayi. Repeat the cycles of BhastrikÄ three to four times, interspersed with Ujjayi breathing. Alternatively, adjust the thumb and finger pressure on the nostrils following the SÅ«rya Bhedana technique. Completely close the left nostril. Keep the right nostril partially open. Inhale and exhale vigorously only through the right nostril for ten to twelve cycles. Close the right nostril. Partially open the left nostril. Repeat the vigorous inhalation and exhalation through the left nostril for an equal number of cycles. Release the fingers from the nostrils. Take a few deep breaths as in Ujjayi. Repeat the cycles on both sides three or four times, performing Ujjayi breathing between repetitions. Lie down in Savasana after completion.', '10_Restorative_Pranayama', NULL, 'I,II,III,IV', 'Bellows Breath', '14/2/2026 4:12pm', 'BhastrikÄ PrÄnÄyÄma
The sound made resembles air rushing through bellows.
Effects: rests the lungs and the diaphragm, prepares them for fresh cycles of BhastrikÄ.', true, NULL, NULL, NULL, NULL, 'à¤­à¤¸à¥à¤¤à¥à¤°à¤¿à¤•à¤¾ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Bellows Breath": ''Bhastra'' (bellows), ''ika'' (diminutive suffix), ''Prana'' (life force, breath), ''Ayama'' (extension, control).', 'Bhastrika employs forceful inhalations and exhalations to purify nadis and generate internal heat. The rapid abdominal contractions stimulate diaphragmatic action and enhance respiratory capacity.', 'Within a square frame, two parallel vertical lines represent the lungs. An open circle sits centrally above the lines, symbolizing the open glottis and the cyclical nature of breath.', true, '/storage/v1/object/public/yoga-cards/206_master_bhasrika_pranayama.webp', '/storage/v1/object/public/audio-assets/206_bhastrikapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 300, "short": 60, "standard": 180}', '[]', false),
	('Sitali Pranayama', '209', 'ÅšÄ«talÄ« PrÄá¹‡ÄyÄma', 'Final: 601', 1, false, NULL, 379, 'Sit in Padmasana, Siddhasana, or Virasana. Keep the back erect and rigid. Keep the head level. Perform the Ja Mudra with the hands. Open the mouth. Form the lips into an ''O''. Lift and curl up the sides and tip of the tongue so it touches the teeth. Protrude the curled tongue out of the lips. Draw in air past the curled tongue with a sibilant sound to fill the lungs completely. Withdraw the tongue. Close the mouth. After full inhalation, lower the head from the nape of the neck to the trunk. Rest the chin in the notch between the collar-bones. Hold the breath for about five seconds. Practice Mula Bandha while holding the breath. Exhale slowly with an aspirate sound through the nose as in Ujjayi. Lift the head. Repeat the cycle for five to ten minutes. Lie down in Savasana after completion.', '10_Restorative_Pranayama', NULL, 'I,II,III', 'Cooling Breath', '14/2/2026 4:12pm', 'Sitali Pranayama
The descriptive meaning of the name is not explicitly provided in the text.
Effects: Cools the system, soothes eyes and ears, beneficial for low fever, biliousness, and thirst, activates liver and spleen, improves digestion.', true, NULL, NULL, NULL, NULL, 'à¤¶à¥€à¤¤à¤²à¥€ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Cooling Breath Technique"', 'Sitali involves inhaling through a curled tongue or pursed lips to create a cooling effect. It primarily focuses on abdominal breathing and parasympathetic activation.', 'Within a square frame, a vertical hairline is centrally placed. A hexagon sits above the line, its vertex pointing downwards and bisecting the vertical line, symbolizing the cooling breath passing through the core.', true, '/storage/v1/object/public/yoga-cards/209_master_sitali_pranayama.webp', '/storage/v1/object/public/audio-assets/209_sitalipranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Eka Pada Rajakapotasana IV', '188', 'Eka PÄda RÄjakapotÄsana IV', 'Final: 547', 40, true, 394, 327, 'Begin in Hanumanasana splits. Extend one leg forward and one leg back. Square the hips. Lengthen the spine. Bend the back knee. Draw the back foot toward the head. Catch the back foot over the head. Maintain the deepest extension. This pose vitalizes the thyroids. This pose also vitalizes the adrenals.', '09_Backbends', NULL, NULL, 'One-Legged King Pigeon Pose IV', '14/2/2026 4:12pm', 'Eka Pada Rajakapotasana Four or King pigeon Four
This pose is done from Hanumanasana splits by bending the back leg and catching the foot over the head.
Effects: Deepest extension, vitalizes thyroids and adrenals.', true, NULL, NULL, NULL, NULL, 'à¤à¤• à¤ªà¤¾à¤¦ à¤°à¤¾à¤œà¤•à¤ªà¥‹à¤¤à¤¾à¤¸à¤¨', 'One-Footed King Pigeon Pose IV', 'This variation emphasizes deep hip flexor opening and spinal extension. The adductors draw inward to stabilize the pose, while the back arches from the thoracic spine.', 'A square frame contains an offset vertical axis, weighted to the left. An equilateral triangle is positioned above the axis, slightly off-center to the right, symbolizing the grounded hip and angled leg.', true, '/storage/v1/object/public/yoga-cards/188_master_eka_pada_rajakapotasana_iv.webp', '/storage/v1/object/public/audio-assets/188_ekapadarajakapotasanaiv.mp3', NULL, NULL, 9, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Paschima Namaskarasana', '233', 'PaÅ›cimÄnamaskÄrÄsana', NULL, 2, false, NULL, NULL, 'Join the palms behind the back, with the fingers pointing down.
Turn the hands toward the spine.
Turn the hands up and raise them between the shoulder blades. Take the shoulders and elbows back and press the palms together.', '12_Preparatory_Recovery', NULL, NULL, 'Reverse Prayer Pose', '22/2/2026 11:03am', 'Paschima Namaskarasana, or Reverse Prayer Pose, is a standing or seated yoga posture where the hands are joined in a prayer position (Anjali Mudra) behind the back, specifically between the shoulder blades with fingers pointing upward. It is a variation of Tadasana (Mountain Pose) that serves as a deep chest opener and shoulder stretch.

Benefits:  - Increases flexibility in the shoulders, wrists, and upper body
  - Improves posture by counteracting slouching and lengthening the spine
  - Opens the chest and diaphragm, enhancing lung capacity and breathing
  - Strengthens the arms, pectoral muscles, and wrist tendons
  - Relieves stress, calms the mind, and reduces negative emotions like anxiety
  - Stimulates the heart and solar plexus chakras
  - Aids digestion and metabolism
  - Helps alleviate conditions like carpal tunnel syndrome and frozen shoulder stiffness', true, NULL, NULL, NULL, NULL, 'à¤ªà¤¶à¥à¤šà¤¿à¤®à¤¾à¤¨à¤®à¤¸à¥à¤•à¤¾à¤°à¤¾à¤¸à¤¨', '"Western Salutation Pose": à¤ªà¤¶à¥à¤šà¤¾à¤¤à¥ (paschat) - west, à¤¨à¤®à¤¸à¥ (namas) - to bow or salute, and à¤†à¤¸à¤¨ (asana) - pose.', 'This pose emphasizes adduction of the scapulae and expansion of the pectoral girdle while grounding through the feet. The spine remains neutral, resisting extension.', 'Within a square frame, two opposing diagonal slashes originate from the top corners, descending and converging towards the center of the bottom edge. A horizontal line bisects the frame, reinforcing the grounding action.', true, '/storage/v1/object/public/yoga-cards/233_master_pascimanamaskarasana.webp', '/storage/v1/object/public/audio-assets/233_PaschimaNamaskarasana.mp3', NULL, NULL, 1, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Sitakari Pranayama', '210', 'ÅšÄ«tkÄrÄ« PrÄá¹‡ÄyÄma', 'Final: 607', 1, false, NULL, 380, 'Sit in Padmasana, Siddhasana, or Virasana. Keep the back erect and rigid. Keep the head level. Perform the JÃ±Äna Mudra with the hands. Keep the tongue flat in its normal state. Keep the lips slightly parted. Protrude only the tip of the tongue between the teeth. Draw in the air through the mouth past the tongue with a sibilant sound to fill the lungs completely. Withdraw the tongue after full inhalation. Close the mouth. Lower the head from the nape of the neck to the trunk. Rest the chin in the notch between the collar-bones just above the breast-bone. This places the head in the Jalandhara Bandha position. Hold the breath for about five seconds. Practice MÅ«la Bandha during retention. Exhale slowly through the nose with an aspirate sound as in Ujjayi. Lift the head. Repeat the cycle for five to ten minutes. Lie down in Savasana after completion.', '10_Restorative_Pranayama', NULL, 'I,II,III', 'Hissing Cooling Breath', '14/2/2026 4:12pm', 'SÄ«tkÄri PrÄnÄyÄma
The breathing technique involves drawing in air with a sibilant, hissing sound.
Effects: cools the system, soothes the eyes and ears, acts as a beneficial aid for low fever, biliousness, and thirst, activates the liver and spleen, and improves digestion.', true, NULL, NULL, NULL, NULL, 'à¤¶à¥€à¤¤à¥à¤•à¤¾à¤°à¥€ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', 'Sitkari Pranayama (Variation of Root Pose)', 'Sitkari Pranayama in this variation initiates with adho mukha svanasana, engaging the serratus anterior to protract the scapulae and stabilize the shoulder girdle. Subsequently, internal rotation of the thighs and lifting of the frontal iliac spines establishes the foundation for uddiyana bandha, promoting diaphragmatic lift.', 'The symbol consists of three intersecting lines converging towards a central point, with a solid bindu (dot) at the intersection, representing the focused energy and convergence of breath during the practice.', true, '/storage/v1/object/public/yoga-cards/210_master_sitkari_pranayama.webp', '/storage/v1/object/public/audio-assets/210_sitakaripranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Chandra Bhedana Pranayama', '217', 'Chandra Bhedana PrÄá¹‡ÄyÄma', 'Final: 613', 2, false, NULL, NULL, 'Sit in a stable meditative asana. Keep the spinal column firm. Soften the spinal muscles to allow the torso to adjust. Lift the inner frame of the chest. Lower the head toward the trunk. Rest the chin in the notch above the breastbone to form the chin lock (Jalandhara Bandha). Place the back of the wrists on the knees. Keep the eyes and ears passive and receptive. Inhale quietly through both nostrils. Raise the right hand toward the face. Form mrigi mudra by bending the index and middle fingers toward the palm. Place the right thumb on the right side of the nose. Place the ring and little fingers on the left side of the nose. Press the thumb to block the right nostril completely. Use the ring and little fingers to narrow the left nasal passage. Inhale slowly and deeply through the left nostril. Fill the lungs to their full capacity. Block both nostrils with the thumb and fingers for one or two seconds. Release the pressure of the thumb on the right nostril. Narrow the right nasal passage with the thumb. Exhale slowly and deeply through the right nostril. Block both nostrils again for a brief pause. Repeat this sequence by inhaling only through the left nostril and exhaling only through the right nostril. Maintain a smooth and steady rhythm for ten to fifteen minutes. Complete the practice with a final inhalation through the left nostril. Finish the entire session with a quiet exhalation through both nostrils. Lower the right hand. Raise the head from the chin lock (Jalandhara Bandha). Relax the body in savasana.', '10_Restorative_Pranayama', NULL, 'I,II,III,IV,V,VI,VII,VIII,IX,X,XI,XII,XIII,XIV,XV,XVI', 'Moon Breath', '14/2/2026 4:12pm', 'Chandra Bhedana prÄá¹‡ÄyÄma
The name refers to the moon.
Effects: Inhalations are done through the left nostril, all exhalations through the right, Pranic energy in all inhalations is channelled through the Ida or chandra nadi, all exhalations pass through the pingala or sÅ«rya nadi, the technique is done in four stages, similar to those of sÅ«rya bhedana.', true, NULL, NULL, NULL, NULL, 'à¤šà¤¨à¥à¤¦à¥à¤°à¤­à¥‡à¤¦à¤¨ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Moon Piercing Breath"', 'Left nostril inhalation stimulates the ida nadi, influencing parasympathetic nervous system activity. Stabilized adduction of the shoulder blades and grounded sacrum creates a steady channel for pranic flow.', 'Within a square frame, a vertical hairline is offset to the left. An equilateral triangle, apex pointing downwards and offset to the right, signifies the lunar energy and grounding.', true, '/storage/v1/object/public/yoga-cards/217_master_chandra_bhedana_pranayama.webp', '/storage/v1/object/public/audio-assets/217_ChandraBhedanaPranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 900, "short": 480, "standard": 600}', '[]', false),
	('Abhyanga', '221', 'Abhyaá¹…ga', NULL, 1, false, NULL, NULL, 'Find a comfortable sitting position with the spine tall. Use the palms and fingers of both hands to press the top of the head. Gradually press and release as the hands move forward over the face, down the neck, and onto the chest. Return to the top of the head and press and release while moving down the back of the neck and around to the chest. To tone the right arm, grasp the fingers of the right hand with the left hand. Press and release firmly and continuously upward along the top of the right arm to the shoulder and across the chest. Repeat the pressing and releasing along the underside of the right arm from the hand to the forearm, shoulder, and chest. Perform the same sequence on the left arm, ensuring both the top and underside are massaged. Maintain firm, gradual, and continuous pressure throughout the process. Complete the routine by allowing the body to feel invigorated and the breath to remain natural.', '11_Ayurvedic_Toning', 'Focus on moving the pressure in the direction of the heart.', NULL, 'Self-Massage', '14/2/2026 4:12pm', 'Abhyanga (Self-Massage)
This is a seated self-massage routine that systematically targets the upper body, covering the head, face, neck, and chest, and includes toning massages for the arms.
Effects: Invigorates and tones the body, improves circulation, enlivens the neuromuscular system, and prepares the mind and body for deeper meditation.', true, NULL, NULL, NULL, NULL, 'à¤…à¤­à¥à¤¯à¤™à¥à¤—', 'Rubbing, anointing; from ''abhi'' (towards, upon) and ''anga'' (limb, body).', 'Abhyanga involves rhythmic strokes towards the heart, stimulating arterial circulation and lymphatic drainage. Precise hand movements align with energy channels (nadis) for optimal flow.', 'Within a square frame, a central vertical line represents the spine. Two diagonal lines intersect this vertical line: one slanting upwards from the bottom left, the other downwards from the top right. A solid bindu marks the intersection point, signifying focused intention.', true, '/storage/v1/object/public/yoga-cards/221_master_abhyanga.webp', '/storage/v1/object/public/audio-assets/221_abhyanga.mp3', NULL, NULL, 11, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', false),
	('Sanchalana', '222', 'SaÃ±cÄlana', NULL, 2, false, NULL, NULL, 'Begin by placing the fingertips at the navel. Using both hands, press and release around the abdomen, gradually moving the pressure upward toward the heart. Shift the hands to the lower back and kidney area; continue the press-and-release motion over the ribs, moving upward toward the heart. Transition to the right foot. Grasp and massage the toes, soles, and the top of the foot. Continue the upward motion through the calves, thighs, and hips, then move across the stomach toward the heart. Repeat this sequence on the left side, starting from the left foot and moving up through the leg and hip, finishing at the heart. Maintain firm yet comfortable pressure throughout the routine to encourage the flow of energy and circulation.', '11_Ayurvedic_Toning', 'Always move the massage pressure toward the heart to support lymphatic and venous return.', NULL, 'Circulation Flow', '14/2/2026 4:12pm', 'Sanchalana (Circulation Flow)
This is a systematic full-body self-massage routine that moves from the feet and torso upward to the heart area.
Effects: Enhances systemic circulation, stimulates lymphatic drainage, supports kidney and digestive function, and promotes a sense of grounded vitality.', true, NULL, NULL, NULL, NULL, 'à¤¸à¤žà¥à¤šà¤¾à¤²à¤¨', '"Setting in motion," from saÃ±- (together) and calana (motion).', 'Sanchalana activates the adductors to stabilize the pose, facilitating spinal extension through the engaged core.', 'Within a square frame, a vertical hairline is offset to the left. A solid bindu sits on the right, bisected by the horizontal midline of the square, representing the grounded yet asymmetrical nature of the pose.', true, '/storage/v1/object/public/yoga-cards/222_master_sancalana.webp', '/storage/v1/object/public/audio-assets/222_sanchalana.mp3', NULL, NULL, 11, '{"flow": 5, "long": 120, "short": 30, "standard": 60}', '[]', false),
	('Jhulana', '223', 'Jhulana', NULL, 2, false, NULL, NULL, 'Lie flat on the back, lengthening the spine and keeping the head and neck long and free. Draw the knees up to the chest and clasp the hands over the knees. Begin to roll slowly and easily from side to side. Maintain a relaxed neck and breathe normally throughout the movement. Perform five rolls to each side. To finish, release the arms and slowly extend the legs out from the hips, allowing the entire body to rest in a state of complete relaxation.', '11_Ayurvedic_Toning', 'Keep the neck completely relaxed and the breath fluid during the rocking motion.', NULL, 'Spinal Rock', '14/2/2026 4:12pm', 'Spinal Rock / Jhulana
This is a simple, gentle supine exercise that uses a rocking motion to release tension and relax the spine and lower back.
Effects: Massages the spinal column, releases tightness in the lumbar region, soothes the nervous system, and promotes physical relaxation before deeper asana practice.', true, NULL, NULL, NULL, NULL, 'à¤à¥à¤²à¤¨à¤¾ à¤²à¥à¤°à¤¹à¤•à¤¾à¤¨à¤¾à¤¸à¤¨', 'Jhulana (à¤à¥‚à¤²à¤¨) translates to ''swinging'' or ''dangling,'' derived from the root ''jhul'' meaning to sway or rock.', 'Jhulanaâ€™s blueprint emphasizes the engagement of core stabilizers to maintain equilibrium while the body suspends. Precise adductor engagement facilitates balanced suspension.', 'Within a square frame, a diagonal slash ascends from the bottom left to the top right, representing dynamic suspension. Two concentric arcs, their open ends facing upwards, are positioned below the slash, suggesting grounded stability.', true, '/storage/v1/object/public/yoga-cards/223_master_jhulana.webp', '/storage/v1/object/public/audio-assets/223_jhulana.mp3', NULL, NULL, 11, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Vajrasana', '224', 'VajrÄsana', NULL, 1, false, NULL, NULL, 'Begin by kneeling and sitting with the buttocks on the heels. The feet should be slightly apart and the big toes crossed. Lengthen the spine, widen the rib cage, and slightly lift the chest while keeping the head and neck long and free. Look straight ahead and breathe easily, placing the hands in the lap with the right hand on top of the left, palms up. As you inhale, lift the buttocks off the heels and come up to a full kneeling position. Keep the spine lengthened, the chest open, and the shoulders relaxed. On the exhalation, slowly lower the body back down to the heels. Repeat the movement smoothly and slowly with even breaths, keeping the front and back of the body active and long.', '11_Ayurvedic_Toning', 'Focus on the synchronization of the breath with the lifting and lowering of the body.', NULL, 'Seat Firming Pose', '14/2/2026 4:12pm', 'Seat Firming Poseâ€”Vajrasana
This exercise is a slow, rhythmic movement performed in a kneeling position, coordinated with deep breathing, that focuses on lengthening the spine and keeping the chest open.
Effects: Strengthens the pelvic region, removes tension from the knees and ankles, and builds a strong foundation for the back.', true, NULL, NULL, NULL, NULL, 'à¤µà¤œà¥à¤°à¤¾à¤¸à¤¨', '"Thunderbolt Pose" or "Diamond Pose" - vajra (à¤µà¤œà¥à¤°) meaning "thunderbolt" or "diamond," and asana (à¤†à¤¸à¤¨) meaning "seat" or "pose."', 'Vajrasana''s structural integrity relies on adductor magnus engagement to protect the knees; the pose facilitates a neutral, elongated spine, achieved through subtle engagement of the core musculature.', 'Within a square frame, a vertical hairline is offset to the left. A solid bindu sits on the right, bisected by the horizontal midline of the square, representing the grounded yet asymmetrical nature of the pose.', true, '/storage/v1/object/public/yoga-cards/224_master_vajrasana.webp', '/storage/v1/object/public/audio-assets/224_vajrasana.mp3', NULL, NULL, 11, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Urdhva Hastasana', '226', 'Åªrdhva HastÄsana', NULL, 1, false, NULL, NULL, 'Begin by standing tall in Tadasana (Mountain Pose) with the feet together and weight evenly distributed. On a deep inhalation, sweep the arms overhead and bring the palms together. Simultaneously lift the chest and gently arch the back, reaching up and slightly behind while lengthening the spine. Maintain a gaze toward the thumbs or slightly upward. Ensure the core remains engaged and the legs stay firm to support the torso. Hold the extension briefly, focusing on the expansion of the ribs, then exhale as you slowly return to a neutral standing position with arms at the sides.', '11_Ayurvedic_Toning', 'Keep the core engaged and legs strong to protect the lower back during the backbend.', NULL, 'Raised Hands Pose', '14/2/2026 4:12pm', 'Hasta Uttanasana (Raised Hands Pose)
A standing posture that involves a gentle backward arch and overhead arm extension to open the front of the body.
Effects: Intensely stretches the spine, chest, and abdomen, expands the lungs to improve breathing capacity, and energizes the entire system. It is a key movement in the Sun Salutation sequence.', true, NULL, NULL, NULL, '19', 'à¤Šà¤°à¥à¤§à¥à¤µ à¤¹à¤¸à¥à¤¤à¤¾à¤¸à¤¨', '"Upward Hands Pose":  *urdhva* (à¤Šà¤°à¥à¤§à¥à¤µ) = upward, raised; *hasta* (à¤¹à¤¸à¥à¤¤) = hand; *asana* (à¤†à¤¸à¤¨) = pose.', 'Urdhva Hastasana establishes the fundamental spinal extension and neutral alignment from the foundation. Scapular stabilization and adductor engagement initiate axial lift.', 'Three lines intersect at a central point, forming an equilateral triangle. A vertical line extends upwards from the apex, bisecting the triangle. The triangle represents the grounded base; the vertical line, spinal extension; the intersection, the integrated core.', true, '/storage/v1/object/public/yoga-cards/226_master_urdhva_hastasana.webp', '/storage/v1/object/public/audio-assets/226_hastauttanasana.mp3', 19.00, NULL, 11, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Surya Bhedana Pranayama', '204', 'SÅ«rya Bhedana PrÄá¹‡ÄyÄma', 'Final: 599 | Int: 598', 2, false, NULL, 371, 'Sit in a comfortable meditative posture such as the lotus pose or the hero pose. Keep the back erect and rigid. Lift the chest toward the chin. Lower the head toward the trunk. Rest the chin in the notch between the collarbones to form the chin lock (Jalandhara Bandha). Stretch the left arm forward. Rest the back of the left wrist on the left knee. Join the index finger and thumb of the left hand to form the ja mudra. Bend the right arm at the elbow. Fold the index and middle fingers of the right hand toward the palm. Keep the right thumb near the right nostril. Place the right ring and little fingers on the left side of the nose. Position the fingertips just below the nasal bone and above the fatty tissue. Press the ring and little fingers to block the left nostril completely. Use the right thumb to narrow the right nasal passage. Align the outer edge of the right nostril parallel to the septum. Inhale slowly and deeply through the right nostril. Fill the lungs to their full capacity. Block the right nostril with the thumb so both sides are closed. Apply the root lock (Mula Bandha) by contracting the pelvic floor.  Hold the breath for five seconds. Release the root lock (Mula Bandha). Keep the right nostril blocked. Open the left nostril partially with the ring and little fingers. Exhale slowly and deeply through the left nostril. Maintain the outer edge of the left nostril parallel to the septum during the out breath. Listen to the steady sound of the air as it passes the fingertips. Keep the eyes and forehead completely passive without strain. Repeat this cycle of inhaling right and exhaling left for five to ten minutes. Finish the final cycle by exhaling through the left nostril. Lower the right hand. Raise the head from the chin lock (Jalandhara Bandha). Lie down in the corpse pose (Savasana).', '10_Restorative_Pranayama', NULL, 'I,II,III,IV,V,VI,VII,VIII,IX,X,XI,XII,XIII,XIV,XV,XVI', 'Sun-Piercing Breath', '14/2/2026 4:12pm', 'SÅ«rya Bhedana PrÄnÄyÄma
Technique

1. Sit in any comfortable position like Padmasana (Image 104), Siddhasana (Image 84) or Virasana (Image 89).

2. Keep the back erect and rigid. Lower the head to the trunk. Rest the chin in the notch between the collar-bones just above the breast-bone. (This is Jalandhara Bandha.)

3. Stretch the left arm. Rest the back of the left wrist on the left knee. Perform JÃ±Äna Mudra with the left hand (as stated in stage 3 of the technique of Ujjayi).

4. Bend the right arm at the elbow. Bend the index and middle fingers towards the palm, keeping them passive. Bring the ring and little fingers towards the thumb. (Image 598)

5. Place the right thumb on the right side of the nose just below the nasal bone, the ring and little fingers on the left side of the nose just below the nasal bone, just above the curve of the fatty tissue of the nostrils above the upper jaw.

6. Press the ring and the little finger to block the left side of the nose completely.

7. With the right thumb, press the fatty tissue on the right side so as to make the outer edge of the right nostril parallel to the lower edge of the cartilage of the septum.

8. The right thumb is bent at the top joint and the tip of the thumb is placed at a right angle to the septum. (Image 599)

9. Now inhale slowly and deeply controlling the aperture of the right nostril with the tip of the thumb nearer the nail. Fill the lungs to the brim (pÅ«raka).

10. Then block the right nostril so that both are now blocked.

11. Hold the breath for about 5 seconds (antara kumbhaka) while practising MÅ«la Bandha (see p. 366).

12. Keeping the right nostril completely blocked, open the left nostril partially and exhale through it slowly and deeply (rechaka).

13. During the exhalation regulate the rhythmic flow of air from the left nostril by adjusting pressure with the ring and little fingers, so that the outer edge of the left nostril is kept parallel to the septum. The pressure should be exerted from the inner sides of the tips of the fingers (away from the nails).

14. This completes one cycle of SÅ«rya Bhedana PrÄnÄyÄma. Continue with more cycles at a stretch from 5 to 10 minutes, according to capacity.

15. All the inhalations in SÅ«rya Bhedana are from the right nostril and all the exhalations from the left nostril.

16. Throughout the process, the passage of air is felt at the tips of the fingers and the thumbs and in the nasal membranes where pressure is applied. The passage of air makes a sound similar to air escaping from a cycle tube. This sound should be maintained constant throughout by varying pressure on the nostrils.

17. The eyes, temples, eyebrows and the skin on the forehead should remain completely passive and show no sign of strain.

18. The mind should be absorbed completely in listening to the proper sound of the passage of air and in maintaining a proper rhythm in breathing.

19. Each inhalation and exhalation should last for the same length of time.

20. The inhalation and the exhalation should not be forced. An even and slow rhythm should be maintained throughout.

21. Lie down in Savasana after completing pranayama. (Image 592)

Effects Increases digestive power, soothes and invigorates the nerves, and cleans the sinuses. Fills lungs more slowly and fully than Ujjayi. Beneficial for persons with low blood pressure.

Note: Those with high blood pressure or heart trouble should not perform breath retention (kumbhaka).', true, NULL, NULL, NULL, NULL, 'à¤¸à¥‚à¤°à¥à¤¯à¤­à¥‡à¤¦à¤¨ à¤ªà¥à¤°à¤¾à¤£à¤¾à¤¯à¤¾à¤®', '"Surya" (sun), "Bhedana" (piercing, activating), "Pranayama" (breath control); sun-piercing breath.', 'This pranayama generates heat via right nostril inhalation. Core engagement stabilizes the lumbar spine, while the diaphragm supports forced exhalation.', 'Within a square frame, a diagonal slash ascends from the bottom left to the top right, representing spinal extension. A hexagon is positioned so that one of its vertexes sits on the diagonal and points towards the upper right corner of the frame, signifying the directed energy flow.', true, '/storage/v1/object/public/yoga-cards/204_master_surya_bhedana_pranayama.webp', '/storage/v1/object/public/audio-assets/204_suryabhedanapranayama.mp3', NULL, NULL, 10, '{"flow": 5, "long": 900, "short": 480, "standard": 600}', '214', false),
	('Ardha Halasana', '234', 'Ardha HalÄsana', '', 1, false, NULL, NULL, 'Initial Position: Lie on your back in a supine position (Savasana). Place your arms alongside your body, palms resting on the ground, and keep your feet together.
Raise Legs: On an inhalation, slowly raise both legs together, keeping them straight (do not bend your knees) until they are at a 90-degree angle to the floor.
Maintain Position: Keep your back, shoulders, and head on the mat. Push your palms down for support and tighten your abdominal muscles.
Breathing and Duration: Maintain a steady, natural breath while holding the pose for 30 seconds to 1 minute, or for about 6 breaths.
Return: While exhaling, slowly lower your legs back to the ground in a controlled manner, without jerking or lifting your head.', '10_Restorative_Pranayama', '', NULL, 'Half Plow Pose', NULL, 'Ardha Halasana, or Half Plough Pose, is a foundational yoga posture where the practitioner lies on their back and lifts their legs to a 90-degree angle. It serves as a gentler version of or preparation for the full Plough Pose (Halasana).

Key benefits include:  - Strengthens the core, abdominal muscles, and lower back
  - Improves digestion and stimulates abdominal organs to relieve constipation and bloating
  - Enhances blood circulation, especially from the legs back to the heart, helping to relieve varicose veins and leg swelling
  - Increases flexibility in the hamstrings, hips, and spine
  - Calms the nervous system to reduce stress, anxiety, and mental fatigue
  - Supports respiratory health by expanding lung capacity
  - May help balance the thyroid gland and metabolism
  - Benefits reproductive health in women by toning pelvic muscles and relieving PMS symptoms', true, NULL, NULL, '36 | II', '80', 'à¤…à¤°à¥à¤§ à¤¹à¤²à¤¾à¤¸à¤¨', '"Half Plough Pose": à¤…à¤°à¥à¤§ (ardha) - half, à¤¹à¤² (hala) - plough, à¤†à¤¸à¤¨ (asana) - pose.', 'Leveraging abdominal strength, the lumbar spine initiates flexion while maintaining a neutral cervical spine. Precise adductor engagement stabilizes the lower limbs.', 'A vertical line representing the spine intersects a horizontal line symbolizing the ground. An open circle is positioned at the intersection. A third line extends upward at a 30-degree angle from the vertical line, representing leg lift.', true, '/storage/v1/object/public/yoga-cards/234_master_ardha_halasana.webp', '/storage/v1/object/public/audio-assets/234_ArdhaHalasana.mp3', 80.00, NULL, 4, '{"flow": 5, "long": 600, "short": 180, "standard": 300}', '[]', true),
	('Mandalasana', '181', 'Máº¡á¹‡dalÄsana', 'Final: 525, 526, 527, 528, 529, 530, 531, 532, 533, 534, 535', 27, false, 381, 316, 'Enter headstand. Stabilize the head in a stationary position. Circle the legs 360 degrees around the head. Maintain the circle motion.', '09_Backbends', NULL, NULL, 'Circle Pose', '14/2/2026 4:12pm', 'Mandalasana Wheel/Orbit
The technique involves circling the legs three hundred sixty degrees around the stationary head in a headstand.
Effects: Promotes longevity, keeps spine in trim.', true, NULL, NULL, NULL, NULL, 'à¤®à¤£à¥à¤¡à¤²à¤¾à¤¸à¤¨', 'Maá¹‡á¸ala (circle, essence) + Ä€sana (seat/posture).', 'Mandalasana establishes a foundational structure via balanced adduction and hip joint articulation. The pose requires precise alignment through the sagittal plane, distributing weight symmetrically around the central axis of the spine.', 'A diagonal slash extending upwards from left to right is anchored by an open circle at its base. This represents the ground connection and angled spinal extension.', true, '/storage/v1/object/public/yoga-cards/181_master_mandalasana.webp', '/storage/v1/object/public/audio-assets/181_mandalasana.mp3', NULL, NULL, 9, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', false),
	('Pavanamuktasana', '236', 'PavanamuktÄsana', '', 1, false, NULL, NULL, 'Lie on your back in a supine position (Shavasana) with legs straight and arms by your side. Exhale and bring both knees toward your chest. Interlock your fingers and clasp your hands around your legs just below the knees. Exhale and lift your head and shoulders off the floor, bringing your chin or forehead toward your knees. Maintain this pose, breathing deeply and comfortably, pressing your abdomen with your thighs. Inhale and slowly lower your head and shoulders, then exhale and release the legs back down to the floor.', NULL, '', NULL, 'Wind-Relieving Pose', NULL, 'Pavanamuktasana, commonly known as the Wind-Relieving Pose or Gas-Release Pose, is a foundational yoga asana.
Benefits: Effectively releases abdominal gas and relieves constipation. Helps ease tension in the lower back and strengthens the spine. Tightens the abdominal muscles and burns fat in the stomach, thighs, and buttocks.
Contraindications: Individuals with severe back or neck issues (e.g., slipped disc), those who have recently undergone abdominal surgery, pregnant women, those suffering from hernia or piles.', true, NULL, NULL, NULL, NULL, 'à¤ªà¤µà¤¨à¤®à¥à¤•à¥à¤¤à¤¾à¤¸à¤¨', NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, 5, '{"flow": 5, "long": 60, "short": 15, "standard": 30}', '[]', true),
	('Nakrasana', '030', 'NakrÄsana', 'Final: 68, 69, 70, 71', 6, false, 105, 78, 'Lie flat on the floor, face downwards. Bend the elbows. Place the palms by the side of the waist. Exhale. Raise the whole body a few inches above the floor. Take a few breaths. Exhale and lunge the whole body a foot forward. Lift the hands and feet simultaneously off the floor. Repeat the forward lunges four or five times. Reverse the movements. Jump back.', '01_Standing_and_Basic', NULL, NULL, 'Crocodile Pose', '14/2/2026 4:12pm', 'Nakrasana
Nakra means a crocodile and this posture consists of several dynamic movements resembling those of a crocodile stalking its prey.
Effects: develops powerful wrists, throws off lethargy of the body, fatigue of the brain, rejuvenates the entire body.', true, NULL, NULL, NULL, NULL, 'à¤¨à¤•à¥à¤°à¤¾à¤¸à¤¨', 'Nakrasana', 'In Nakrasana, the prone position facilitates extension of the thoracic spine by engaging the erector spinae muscles. Simultaneous contraction of the gluteus maximus and hamstrings promotes posterior pelvic tilt, stabilizing the sacroiliac joint.', 'The symbol consists of two parallel lines, representing balance and alignment, with an open circle above them, symbolizing the openness to new growth and the continuous flow of energy (prana) in the practice of Nakrasana.', true, '/storage/v1/object/public/yoga-cards/030_master_nakrasana.webp', '/storage/v1/object/public/audio-assets/030_nakrasana.mp3', NULL, NULL, 7, '{"flow": 5, "long": 30, "short": 10, "standard": 15}', '[]', false),
	('Nauli', '202', 'Nauli', 'Final: 595, 596', 16, false, NULL, 357, 'Stand in Tadasana. Spread the legs a foot apart. Bend slightly at the knees. Stoop forward. Place the hands with the fingers spread wide on the thighs. The hands should be just above the knees. Lower the head until the chin rests in the notch between the collar-bones. Inhale deeply. Exhale quickly so all air is forced from the lungs in a rush. Hold the breath without any inhalation. Pull the whole abdominal region back towards the spine. The area between the pelvic rim and the floating ribs on both sides should be made passive to create hollowness. Push the abdominal recti forward at the same time. Maintain this position from five to ten seconds. Relax the grip on the recti. Go back to the position described in paragraph six. Relax the abdomen. Inhale slowly. Take a few deep breaths. Repeat the cycle six to eight times at a stretch. Repeat the entire process only once every twenty-four hours. Practise Nauli on an empty stomach. Practise Nauli after evacuating the bladder. Practise Nauli after evacuating the bowels.', '10_Restorative_Pranayama', NULL, NULL, 'Abdominal Churning', '14/2/2026 4:12pm', 'Nauli or Lauliki
The process conveys some idea of a large wave or surge, where the abdominal muscles and organs are made to move laterally and vertically in a surging motion, similar to the pitching of a boat on a stormy sea.
Effects: The abdominal recti are strengthened, the other effects are the same as those of Uddiyana Bandha.', true, NULL, NULL, NULL, NULL, 'à¤¨à¥Œà¤²à¥€', '"Churning the abdomen"; from *nau* (boat, navel) and *li* (to cling, dissolve).', 'Nauli kriya isolates and rotates the abdominal muscles, particularly the rectus abdominis. This action strengthens abdominal wall and stimulates digestion via peristalsis.', 'Two parallel lines define the grounded foundation. A hexagon sits above, its vertex pointing downwards, illustrating the concentrated core engagement.', true, '/storage/v1/object/public/yoga-cards/202_master_nauli.webp', '/storage/v1/object/public/audio-assets/202_nauli.mp3', NULL, NULL, 10, '{"flow": 5, "long": 180, "short": 60, "standard": 120}', '[]', false),
	('Dwi Pada Koundinyasana', '158', 'Dwi PÄda Koá»¥á¹‡dinyÄsana', 'Final: 438 | Int: 434, 435, 436, 437', 22, true, 330, 275, 'Place your hands on the mat to the left side of your hips. Your fingers point forward. Your hands are shoulder-width apart. Shift your weight onto your hands. Lean forward. Engage your core muscles. Place your knees on your upper arms. Lift your feet off the mat. Balance on your hands. Stretch your legs out sideways. Keep your legs parallel to the floor. Maintain the arm balance. Focus your gaze forward. Slowly bend your legs. Relax your body.', '08_Advanced_Leg_behind_Head', 'Typo in book: final pose is 438, not 458', NULL, 'Two-Legged Koundinya Pose', '14/2/2026 4:12pm', 'Dwi Pada Koundinyasana or Sage Koundinya''s pose
