	(6, 'Surya Namaskar B', '001 | 10 | [Samasthiti] Action: Exhale, stand tall. Focus: Center the body.
017 | 12 | [Utkatasana] Action: Inhale, bend knees, sweep arms up. Focus: Weight in heels.
020 | 12 | [Uttanasana] Action: Exhale, dive forward. Focus: Straighten legs gently.
020 | 10 | [IV] Action: Inhale, lift chest. Focus: Lengthen spine.
029 | 12 | [Chaturanga Dandasana] Action: Exhale, step/jump back and lower. Focus: Keep core engaged.
032 | 12 | [Urdhva Mukha Svanasana] Action: Inhale, open chest. Focus: Shoulders back.
033 | 10 | [Adho Mukha Svanasana] Action: Exhale, hips high. Focus: Press through palms.
007 | 15 | [I] Action: Inhale, step Right foot forward, reach up. Focus: Back heel grounded.
029 | 12 | [Chaturanga Dandasana] Action: Exhale, hands down, step back, lower. Focus: Smooth transition.
032 | 12 | [Urdhva Mukha Svanasana] Action: Inhale, lift heart. Focus: Lift thighs.
033 | 10 | [Adho Mukha Svanasana] Action: Exhale, hips high. Focus: Reset breath.
007 | 15 | [I] Action: Inhale, step Left foot forward, reach up. Focus: Square hips.
029 | 12 | [Chaturanga Dandasana] Action: Exhale, hands down, step back, lower. Focus: Keep elbows tucked.
032 | 12 | [Urdhva Mukha Svanasana] Action: Inhale, open chest. Focus: Gaze slightly up.
033 | 50 | [Adho Mukha Svanasana] Action: Exhale, hips back and up. Focus: Hold for 5 steady breaths.
020 | 10 | [IV] Action: Inhale, step/jump forward, lift chest. Focus: Flat back.
020 | 12 | [Uttanasana] Action: Exhale, fold deeply. Focus: Crown of head to floor.
017 | 12 | [Utkatasana] Action: Inhale, bend knees, sweep arms up. Focus: Squeeze inner thighs.
001 | 5  | [Samasthiti] Action: Exhale, stand tall, arms by sides. Focus: Ground and breathe.', '2026-04-28T02:28:15.887Z', NULL, true, 55, '[{"note": "Action: Exhale, stand tall. Focus: Center the body.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "001", "duration": 5, "stage_id": null}, {"note": "Action: Inhale, bend knees, sweep arms up. Focus: Weight in heels.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "017", "duration": 5, "stage_id": null}, {"note": "Action: Exhale, dive forward. Focus: Straighten legs gently.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "020", "duration": 5, "stage_id": null}, {"note": "Action: Inhale, lift chest. Focus: Lengthen spine.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "020", "duration": 5, "stage_id": 147}, {"note": "Action: Exhale, step/jump back and lower. Focus: Keep core engaged.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "029", "duration": 5, "stage_id": null}, {"note": "Action: Inhale, open chest. Focus: Shoulders back.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "032", "duration": 5, "stage_id": null}, {"note": "Action: Exhale, hips high. Focus: Press through palms.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "033", "duration": 30, "stage_id": null}, {"note": "Action: Inhale, step Right foot forward, reach up. Focus: Back heel grounded.", "side": "R", "tier": null, "type": "pose", "props": [], "pose_id": "007", "duration": 5, "stage_id": 164}, {"note": "Action: Exhale, hands down, step back, lower. Focus: Smooth transition.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "029", "duration": 5, "stage_id": null}, {"note": "Action: Inhale, lift heart. Focus: Lift thighs.", "side": null, "tier": null, "type": "pose", "props": [], "pose_id": "032", "duration": 5, "stage_id": null}, {"note": "Action: Exhale, hips high. Focus: Res